import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { Form, Button } from 'react-bootstrap';

function AddCompanyItem() {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('');
  const history = useHistory();

  const handleSubmit = (e) => {
    e.preventDefault();

    axios.post('/api/company-items', { name, description, category })
      .then(response => {
        history.push('/company-items');
      })
      .catch(error => {
        console.error('There was an error adding the company item!', error);
      });
  };

  return (
    <div className="container mt-5">
      <h1>Add Company Item</h1>
      <Form onSubmit={handleSubmit}>
        <Form.Group>
          <Form.Label>Name</Form.Label>
          <Form.Control type="text" value={name} onChange={(e) => setName(e.target.value)} required />
        </Form.Group>
        <Form.Group>
          <Form.Label>Description</Form.Label>
          <Form.Control type="text" value={description} onChange={(e) => setDescription(e.target.value)} required />
        </Form.Group>
        <Form.Group>
          <Form.Label>Category</Form.Label>
          <Form.Control type="text" value={category} onChange={(e) => setCategory(e.target.value)} required />
        </Form.Group>
        <Button type="submit" className="btn btn-primary mt-3">Add Company Item</Button>
      </Form>
    </div>
  );
}

export default AddCompanyItem;
